using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" and direct SQL queries reference c.Discriminator.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 breaking change: id values changed from "Product|{Key}" to just "{Key}".
            // Existing 500K documents have ids like "Product|123".
            b.HasDiscriminatorInJsonId();

            // EF9 breaking change: key property now maps directly to JSON "id", removing the
            // shadow __id property. Existing documents store Id separately from the resource id.
            b.HasShadowId();

            // EF9 breaking change: HasIndex now throws (Cosmos indexes all properties by default).
            // Removed: b.HasIndex(p => p.Sku);
            // Manage indexing policy via the Azure Portal if needed.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

