{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") in the model.
        // EF9 breaking change: SQL queries must now project with VALUE.
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF9 breaking change: sync I/O (ToList, SaveChanges) now throws by default.
        // Use async APIs exclusively.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

